import{u as e}from"./index.95f2040e.js";import{_ as n,c as i,o as s,f as t}from"./entry.79f37cee.js";import"./vue.f36acd1f.494dcfe6.js";const a={class:"row"},r=t('<div class="col-xs-12 col-md-offset-1 col-lg-offset-2 col-lg-9 col-md-10" data-v-3e599fdf><h2 class="z-100" data-v-3e599fdf> Mein Angebot </h2><h1 class="z-100" data-v-3e599fdf> Leadership Coaching </h1><h3 class="z-100" data-v-3e599fdf>Führen in agilen Organisationen. Gemeinsam wachsen und Potenzial entfalten</h3><p class="z-100" data-v-3e599fdf>Teams und Organisationen, die auf Selbstorganisation setzen, erfordern neue Führungsansätze und Kompetenzen. Führungsrollen verändern sich und insbesondere die Verteilung von Verantwortung auf mehrere Schultern bringt neue Fragen und Herausforderungen mit sich.</p><p class="z-100" data-v-3e599fdf>Im Leadership Coaching können wir über diese und weitere Fragen sprechen:</p><ul class="z-100" data-v-3e599fdf><li data-v-3e599fdf>Wie finde ich meine Rolle als Führungsperson in der agilen Organisation?</li><li data-v-3e599fdf>Wie funktioniert Führung in selbstorganisierten Teams?</li><li data-v-3e599fdf>Wie kann ich meine Stärken optimal nutzen, wo will ich mich weiterentwickeln?</li><li data-v-3e599fdf>Wie delegiere ich erfolgreich Verantwortung im Team oder Unternehmen?</li><li data-v-3e599fdf>Welchen Rahmen brauchen selbstorganisierte Teams?</li><li data-v-3e599fdf>Wie gestalte ich die Mitarbeiterentwicklung und Feedback-Gespräche?</li><li data-v-3e599fdf>Wie erkenne ich Konflikte und wie gehe ich mit ihnen um?</li><li data-v-3e599fdf>Wie kann ich schwierige Situationen und Gespräche erfolgreich meistern?</li></ul><p class="z-100" data-v-3e599fdf>Gemeinsam finden wir Antworten auf deine Fragen und entwickeln ein stimmiges Führungsverständnis für dich.</p><h2 class="z-100" data-v-3e599fdf>So sieht unsere Zusammenarbeit aus</h2><p class="z-100" data-v-3e599fdf>Wir vereinbaren ein unverbindliches Erstgespräch, in dem wir uns über dein Anliegen unterhalten. Im Anschluss erhältst du ein Angebot von mir.</p><p class="z-100" data-v-3e599fdf>Wir starten mit 6 Terminen mit einer Länge von 90 bis 120 Minuten. Im Rahmen des ersten Termins machen wir eine Analyse des Status quo, priorisieren deine Themen und steigen in den ersten Themenbereich ein. In den weiteren Sessions nehmen wir uns jeweils einen thematischen Schwerpunkt vor. Daneben bietet der Termin Raum für aktuelle Anliegen, die sich aus dem Tagesgeschäft ergeben.</p><p class="z-100" data-v-3e599fdf>Die Coaching-Sessions finden online oder in meinem Hamburger Büro statt.</p></div>',1),d=[r],o={name:"leadershipCoaching"},l=Object.assign(o,{setup(c){return e({title:"Moderne Führung",ogTitle:"Moderne Führung",ogDescription:"Teams und Organisationen, die auf Agilität und Selbstorganisation setzen, erfordern neue Führungsansätze und Kompetenzen. Du bist in einer Führungsrolle und möchtest dich weiterentwickeln? Gemeinsam finden wir Antworten auf deine Fragen und entwickeln ein stimmiges Führungsverständnis für dich.",description:"Teams und Organisationen, die auf Agilität und Selbstorganisation setzen, erfordern neue Führungsansätze und Kompetenzen. Du bist in einer Führungsrolle und möchtest dich weiterentwickeln? Gemeinsam finden wir Antworten auf deine Fragen und entwickeln ein stimmiges Führungsverständnis für dich."}),(h,u)=>(s(),i("div",a,d))}}),p=n(l,[["__scopeId","data-v-3e599fdf"]]);export{p as default};
